import{_ as t,o,c as n,a0 as a}from"./chunks/framework.BWpMpcZ2.js";const u=JSON.parse('{"title":"AI Assist","description":"","frontmatter":{},"headers":[],"relativePath":"ai-assist.md","filePath":"ai-assist.md"}'),s={name:"ai-assist.md"};function i(r,e,l,h,c,d){return o(),n("div",null,[...e[0]||(e[0]=[a(`<h1 id="ai-assist" tabindex="-1">AI Assist <a class="header-anchor" href="#ai-assist" aria-label="Permalink to &quot;AI Assist&quot;">​</a></h1><p>The AI Assist panel is your main interface for writing with AI. You can toggle between <strong>Edit</strong> and <strong>Chat</strong> modes at any time during a session.</p><h2 id="edit-mode" tabindex="-1">Edit Mode <a class="header-anchor" href="#edit-mode" aria-label="Permalink to &quot;Edit Mode&quot;">​</a></h2><p>Use Edit mode when you want the AI to modify or add content. The behavior depends on whether you have text selected or just a cursor placed.</p><h3 id="replace-with-text-selected" tabindex="-1">Replace (with text selected) <a class="header-anchor" href="#replace-with-text-selected" aria-label="Permalink to &quot;Replace (with text selected)&quot;">​</a></h3><ol><li><strong>Highlight</strong> the text you want to change.</li><li>Click the floating <strong>+ Add to Assist</strong> button that appears above the selection.</li><li>Type your instruction (e.g., &quot;Make this more dramatic&quot;, &quot;Shorten to two sentences&quot;).</li><li>Press Enter or click submit.</li><li>The AI rewrites only the selected portion -- surrounding text stays untouched.</li></ol><p><strong>How replacement works:</strong></p><p>The backend finds which paragraph contains your selection and extracts a three-paragraph window:</p><ul><li>Paragraph above (context)</li><li>Target paragraph (contains your selection)</li><li>Paragraph below (context)</li></ul><p>The Writer agent receives this context plus your instruction and generates new text. The generated text then replaces your selected content directly -- the frontend deletes the selection and inserts the AI output in its place.</p><p>The Writer is instructed to return either a short snippet (if you asked to tweak a specific phrase) or a full rewrite (if you asked to rewrite the entire paragraph). Either way, only your selection is replaced -- nothing else in the document is touched.</p><h3 id="insert-with-cursor-only" tabindex="-1">Insert (with cursor only) <a class="header-anchor" href="#insert-with-cursor-only" aria-label="Permalink to &quot;Insert (with cursor only)&quot;">​</a></h3><ol><li><strong>Place your cursor</strong> where you want new content to appear.</li><li>Open the AI Assist panel and switch to <strong>Edit Document</strong>.</li><li>Type your instruction (e.g., &quot;Write a paragraph about the castle&#39;s architecture&quot;).</li><li>Press Enter.</li><li>The AI generates new content and inserts it at your cursor position.</li></ol><p><strong>How insertion works:</strong></p><p>The backend identifies the paragraph containing your cursor and sends the same three-paragraph window (above, target, below) as context. The AI generates fresh content that gets inserted at the cursor -- nothing is replaced, no text is deleted.</p><h2 id="chat-mode" tabindex="-1">Chat Mode <a class="header-anchor" href="#chat-mode" aria-label="Permalink to &quot;Chat Mode&quot;">​</a></h2><p>Use Chat mode for brainstorming, asking questions, or discussing your content with the AI.</p><ul><li>The AI has access to your full <strong>conversation history</strong> within the session.</li><li>If you have text selected when you send a message, the AI can see what you&#39;ve highlighted.</li><li>Chat mode <strong>does not modify your document</strong> -- it only responds conversationally.</li><li>You can switch between Edit and Chat modes freely without losing session context.</li></ul><h2 id="context-window" tabindex="-1">Context Window <a class="header-anchor" href="#context-window" aria-label="Permalink to &quot;Context Window&quot;">​</a></h2><p>In Edit mode, the AI always receives exactly three paragraphs of surrounding context:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[Paragraph above]</span></span>
<span class="line"><span>[Your target -- either selected text or the paragraph containing cursor]</span></span>
<span class="line"><span>[Paragraph below]</span></span></code></pre></div><p>This keeps token usage low and focused, which is especially important for smaller local models. The Writer agent is instructed to never echo or reproduce the surrounding paragraphs -- only to produce new text for the target.</p><h2 id="reasoning-thinking" tabindex="-1">Reasoning &amp; Thinking <a class="header-anchor" href="#reasoning-thinking" aria-label="Permalink to &quot;Reasoning &amp; Thinking&quot;">​</a></h2><p>Some AI models produce internal reasoning (or &quot;thinking&quot;) before generating their final response. When this happens, the reasoning text appears in a collapsible <strong>Thought Process</strong> dropdown above the response.</p><h3 id="during-streaming" tabindex="-1">During Streaming <a class="header-anchor" href="#during-streaming" aria-label="Permalink to &quot;During Streaming&quot;">​</a></h3><p>While the model is generating, the reasoning text streams in live and the dropdown opens automatically. You can close it to focus on the final output as it arrives.</p><h3 id="in-history" tabindex="-1">In History <a class="header-anchor" href="#in-history" aria-label="Permalink to &quot;In History&quot;">​</a></h3><p>Past AI responses that included reasoning show a collapsed <strong>Thought Process</strong> button. Click it to review the model&#39;s reasoning after the fact.</p><h3 id="how-to-control-it" tabindex="-1">How to Control It <a class="header-anchor" href="#how-to-control-it" aria-label="Permalink to &quot;How to Control It&quot;">​</a></h3><p>You can configure the thinking behavior per endpoint in <strong>Settings &gt; Endpoints</strong>:</p><ul><li><strong>Thinking Model toggle</strong>: Turn reasoning on or off for a specific endpoint. When off, the model&#39;s output passes through unmodified.</li><li><strong>Custom Thinking Tags</strong>: Some models use non-standard reasoning tags. You can add custom <code>(open, close)</code> tag pairs so the system can strip them from the output you see.</li><li><strong>Show thinking by default</strong>: Set whether the Thought Process dropdown opens automatically for new responses.</li></ul><blockquote><p>See <a href="./configuration/endpoints.html#reasoning-settings">Endpoints &gt; Reasoning Settings</a> for full configuration details.</p></blockquote><h2 id="debugging-telemetry" tabindex="-1">Debugging &amp; Telemetry <a class="header-anchor" href="#debugging-telemetry" aria-label="Permalink to &quot;Debugging &amp; Telemetry&quot;">​</a></h2><p>Each AI request and response is logged locally. Click the <strong>telemetry / book icon</strong> in the AI Assist panel to open the inspector, which shows:</p><ul><li>The last API request (your full input)</li><li>The complete system prompt sent to the AI</li><li>The AI&#39;s raw output response</li><li>Session context and remaining context window</li><li>Total conversation history for the session</li></ul><p>Use this to understand why the AI responded a certain way, debug quality issues, or inspect what prompts were used.</p><blockquote><p>See <a href="./configuration/debugging.html">Debugging</a> for more details on logs, prompt templates, and local telemetry.</p></blockquote>`,37)])])}const g=t(s,[["render",i]]);export{u as __pageData,g as default};
